package be.schaubroeck.lpb.rkm.rekenmotor.voorbereiding;

import be.schaubroeck.lpb.rkm.rekenmotor.RekenTijd;
import be.schaubroeck.lpb.tools.Admin;
import be.schaubroeck.lpb.tools.ElektronischeVoorbereiding;
import be.schaubroeck.lpb.tools.KalAfsluiten;
import be.schaubroeck.lpb.tools.KalOpdrachtLooncode;
import be.schaubroeck.lpb.tools.Opdracht;
import be.schaubroeck.lpb.tools.criteria.CriteriaBuilder;
import be.schaubroeck.lpb.tools.criteria.Criterium;
import be.schaubroeck.lpb.tools.enumtypes.Hoedanigheid;
import be.schaubroeck.lpb.tools.enumtypes.KalenderPrestatielijstStatus;
import be.schaubroeck.lpb.tools.enumtypes.Rekengroep;
import be.schaubroeck.lpb.tools.enumtypes.SoortVrb;
import be.schaubroeck.lpb.tools.enumtypes.StatusVoorbereiding;
import be.schaubroeck.lpb.tools.exception.MessageException;
import be.schaubroeck.lpb.tools.service.KalAfsluitenService;
import be.schaubroeck.lpb.tools.service.OpdrachtService;
import be.schaubroeck.temporal.interval.LocalDateInterval;
import be.schaubroeck.temporal.interval.Month;
import be.schaubroeck.temporal.util.TemporalContext;
import be.schaubroeck.util.persistence.Identifiable;
import com.google.common.collect.ImmutableSet;
import lombok.Builder;
import lombok.Data;
import lombok.extern.slf4j.Slf4j;
import org.joda.time.LocalDate;
import org.joda.time.LocalDateTime;

import java.util.ArrayList;
import java.util.Arrays;
import java.util.Collection;
import java.util.EnumSet;
import java.util.HashSet;
import java.util.List;
import java.util.Set;
import java.util.stream.Collectors;

@Data
@Slf4j
@Builder
public class RekenVoorbereiding {

    private static final Set<SoortVrb> KALENDER_VOORBEREIDING_SOORTEN =
            ImmutableSet.of(SoortVrb.EKAL_KAL, SoortVrb.EKAL_SUP, SoortVrb.EKAL_INH, SoortVrb.EKAL_MTC, SoortVrb.EKAL_CHQS, SoortVrb.EKAL_BER_RSLT);
    private static final Set<KalenderPrestatielijstStatus> STATUSSEN =
            ImmutableSet.of(KalenderPrestatielijstStatus.RM2_READY, KalenderPrestatielijstStatus.RM2_BUSY, KalenderPrestatielijstStatus.RM2_LOCK);
    private static final Set<StatusVoorbereiding> KALENDER_VB_STATUS = EnumSet
            .of(StatusVoorbereiding.RM2_GEREKEND, StatusVoorbereiding.RM2_GEREKEND_MET_WAARSCHUWINGEN, StatusVoorbereiding.RM2_GEREKEND_MET_FOUTEN,
                    StatusVoorbereiding.RM2_BEZIG_MET_REKENEN, StatusVoorbereiding.RM2_REKENEN_LOCKED);

    private final ElektronischeVoorbereiding elektronischeVoorbereiding;
    private Admin admin;
    private boolean isKalenderOpdracht;
    private int kalAfsluitenOpdrachtId;
    private int kalAfsluitenId;
    private Opdracht opdracht;

    private OpdrachtService opdrachtService;
    private KalAfsluitenService kalAfsluitenService;


    public Month getPeriode() {
        return new Month(elektronischeVoorbereiding.getJaar(), elektronischeVoorbereiding.getMaand());
    }

    public boolean isEkalenderVoorbereiding() {
        return KALENDER_VOORBEREIDING_SOORTEN.contains(elektronischeVoorbereiding.getSoort());
    }

    public boolean isEkalenderVoorbereidingStatus(StatusVoorbereiding status) {
        return KALENDER_VB_STATUS.contains(status);
    }

    public RekenTijd getRekenTijd(LocalDateTime rekenTijdstip) {
        return getRekenTijd(getPeriode(), rekenTijdstip);
    }

    public RekenTijd getRekenTijd(LocalDateInterval maand, LocalDateTime rekenTijdstip) {
        LocalDate beslagDatum = elektronischeVoorbereiding.getBeslagDatum();
        if (beslagDatum.isBefore(maand.getStart())) {
            beslagDatum = maand.getStart();
        }
        return new RekenTijd(maand, elektronischeVoorbereiding.getRekenDatum(), elektronischeVoorbereiding.getBoekDatum(), beslagDatum, rekenTijdstip);
    }

    public boolean getMetRegulagenda() {
        return elektronischeVoorbereiding.getMetRegulagenda();
    }

    public List<Opdracht> findOpdrachten() {
        List<Opdracht> opdrachten;
        if (isKalenderOpdracht() && getOpdracht() != null) {
            log.info("vbid {} findOpdrachten isKalenderOpdracht", elektronischeVoorbereiding.getId());
            opdrachten = Arrays.asList(getOpdracht());
        } else if (isEkalenderVoorbereiding()) {
            return bepaalTeRekenenOpdrachtenKalenderVoorbereiding();
        } else {
            return bepaalTeRekenenOpdrachtenVoorbereiding();
        }
        return opdrachten;
    }

    private List<Opdracht> bepaalTeRekenenOpdrachtenKalenderVoorbereiding() {
        log.info("vbid {} bepaalTeRekenenOpdrachtenKalenderVoorbereiding", elektronischeVoorbereiding.getId());
        KalAfsluiten kalAfsluiten = bepaalKalAfsluiten();

        List<Opdracht> opdrachten = new ArrayList<>();
        if (kalAfsluiten != null) {
            log.info("vbid {} kalAfsluiten {}", elektronischeVoorbereiding.getId(), kalAfsluiten.getId());
            Set<KalenderPrestatielijstStatus> nietToepasselijkeStatussen = new HashSet<>();
            for (KalOpdrachtLooncode opdrachtLooncode : kalAfsluiten.getKalOpdrachtLooncodes()) {
                if (STATUSSEN.contains(opdrachtLooncode.getStatus()) || opdrachtLooncode.getVerwijderd()) {
                    opdrachten.add(opdrachtLooncode.getOpdracht());
                } else {
                    nietToepasselijkeStatussen.add(opdrachtLooncode.getStatus());
                }
            }
            log.info("vbid {} Niet toepasselijke Status {}", elektronischeVoorbereiding.getId(), nietToepasselijkeStatussen);
        }
        return opdrachten;
    }

    private KalAfsluiten bepaalKalAfsluiten() {
        try {
            TemporalContext.getInstance().setActualInterval(getPeriode());
            return kalAfsluitenService.getById(admin, getKalAfsluitenId(),
                    "kalOpdrachtLooncodes{opdracht,kalOpdrachtLooncodeSlices}");
        } finally {
            TemporalContext.getInstance().clearActualInterval();
        }
    }

    private List<Opdracht> bepaalTeRekenenOpdrachtenVoorbereiding() {
        log.info("vbid {} bepaalTeRekenenOpdrachtenVoorbereiding niet kalender voorbereiding", elektronischeVoorbereiding.getId());
        ElektronischeVoorbereiding voorbereiding = getElektronischeVoorbereiding();
        CriteriaBuilder cb = new CriteriaBuilder();
        cb.and("werkgever.werkgeverNr", Criterium.EQ(voorbereiding.getWerkgeverNummer()));
        if (voorbereiding.getHoedanigheid() != null) {
            cb.and("opdrachtSlices.hoedanigheidCode", Criterium.EQ(voorbereiding.getHoedanigheid().getCode()));
        } else if (voorbereiding.getRekengroep() != null) {
            cb.and("opperSlices.weddeBerekening.rekenGroep", Criterium.EQ(voorbereiding.getRekengroep().getCode()));
        } else {
            throw new MessageException("Ongeldige voorbereiding voor rekenen");
        }

        List<Opdracht> opdrachten;
        try {
            TemporalContext.getInstance().setActualInterval(new Month(voorbereiding.getJaar(), voorbereiding.getMaand()));
            opdrachten = opdrachtService.findByCriteria(admin, cb);
        } finally {
            TemporalContext.getInstance().clearActualInterval();
        }
        return opdrachten;
    }

    public Hoedanigheid getHoedanigheid() {
        return elektronischeVoorbereiding.getHoedanigheid();
    }

    public Rekengroep getRekengroep() {
        return elektronischeVoorbereiding.getRekengroep();
    }

    private <T extends Identifiable> String toStringOfIds(Collection<T> collecton) {
        return collecton.stream().map(T::getId).collect(Collectors.toSet()).toString();
    }
}
